import type { Required } from 'utility-types';
import { createContextHook } from '@universe-design/react-utilities';
import type { AvatarProps } from './Avatar';

export const { Provider: AvatarGroupContextProvider, useContext: useAvatarGroupContext } = createContextHook<
  Required<Pick<AvatarProps, 'size' | 'shape'>>
>('AvatarGroupContext', {
  strict: false,
  defaultValue: {
    size: 'medium',
    shape: 'circle',
  },
});
